  1→/**
  2→ * OutdatedAssetsList Component
  3→ *
  4→ * Displays paginated table of assets with overdue vulnerabilities
  5→ * Features:
  6→ * - Pagination with page size selection
  7→ * - Sorting by columns
  8→ * - Search by asset name
  9→ * - Severity filter
 10→ * - Last updated timestamp
 11→ * - Refresh button
 12→ *
 13→ * Feature: 034-outdated-assets
 14→ * Task: T027-T028
 15→ * User Story: US1 - View Outdated Assets (P1)
 16→ * Spec reference: spec.md, wireframes/01-outdated-assets-list.md
 17→ */
 18→
 19→import React, { useState, useEffect } from 'react';
 20→import {
 21→  getOutdatedAssets,
 22→  getLastRefreshTimestamp,
 23→  getAdDomains,
 24→  triggerRefresh,
 25→  getRefreshStatus,
 26→  exportOutdatedAssets,
 27→  type OutdatedAsset,
 28→  type OutdatedAssetsPage,
 29→  type OutdatedAssetsParams,
 30→  type RefreshJob
 31→} from '../services/outdatedAssetsApi';
 32→import { formatDistanceToNow } from 'date-fns';
 33→
 34→const OutdatedAssetsList: React.FC = () => {
 35→  const [assets, setAssets] = useState<OutdatedAsset[]>([]);
 36→  const [loading, setLoading] = useState<boolean>(true);
 37→  const [error, setError] = useState<string | null>(null);
 38→  const [lastRefresh, setLastRefresh] = useState<string | null>(null);
 39→  const [refreshing, setRefreshing] = useState<boolean>(false);
 40→  const [refreshJob, setRefreshJob] = useState<RefreshJob | null>(null);
 41→  const [pollIntervalId, setPollIntervalId] = useState<NodeJS.Timeout | null>(null);
 42→
 43→  // Pagination state
 44→  const [currentPage, setCurrentPage] = useState<number>(0);
 45→  const [pageSize, setPageSize] = useState<number>(20);
 46→  const [totalPages, setTotalPages] = useState<number>(0);
 47→  const [totalElements, setTotalElements] = useState<number>(0);
 48→
 49→  // Filter/search state
 50→  const [searchTerm, setSearchTerm] = useState<string>('');
 51→  const [minSeverity, setMinSeverity] = useState<string>('');
 52→  const [adDomain, setAdDomain] = useState<string>('');
 53→  const [adDomainOptions, setAdDomainOptions] = useState<string[]>([]);
 54→  const [sortField, setSortField] = useState<string>('assetName');
 55→  const [sortDirection, setSortDirection] = useState<string>('asc');
 56→
 57→  // Export state
 58→  const [exporting, setExporting] = useState<boolean>(false);
 59→
 60→  /**
 61→   * Fetch outdated assets from API
 62→   */
 63→  const fetchAssets = async () => {
 64→    setLoading(true);
 65→    setError(null);
 66→
 67→    try {
 68→      const params: OutdatedAssetsParams = {
 69→        page: currentPage,
 70→        size: pageSize,
 71→        sort: `${sortField},${sortDirection}`
 72→      };
 73→
 74→      if (searchTerm.trim()) {
 75→        params.searchTerm = searchTerm.trim();
 76→      }
 77→
 78→      if (minSeverity) {
 79→        params.minSeverity = minSeverity as any;
 80→      }
 81→
 82→      if (adDomain) {
 83→        params.adDomain = adDomain;
 84→      }
 85→
 86→      const page: OutdatedAssetsPage = await getOutdatedAssets(params);
 87→
 88→      setAssets(page.content);
 89→      setTotalPages(page.totalPages);
 90→      setTotalElements(page.totalElements);
 91→      setCurrentPage(page.number);
 92→    } catch (err: any) {
 93→      console.error('Failed to fetch outdated assets:', err);
 94→      setError(err.response?.data?.message || 'Failed to load outdated assets');
 95→    } finally {
 96→      setLoading(false);
 97→    }
 98→  };
 99→
100→  /**
101→   * Fetch last refresh timestamp
102→   */
103→  const fetchLastRefresh = async () => {
104→    try {
105→      const timestamp = await getLastRefreshTimestamp();
106→      setLastRefresh(timestamp);
107→    } catch (err) {
108→      console.error('Failed to fetch last refresh timestamp:', err);
109→    }
110→  };
111→
112→  /**
113→   * Fetch available AD domains for filter dropdown
114→   */
115→  const fetchAdDomains = async () => {
116→    try {
117→      const domains = await getAdDomains();
118→      setAdDomainOptions(domains);
119→    } catch (err) {
120→      console.error('Failed to fetch AD domains:', err);
121→    }
122→  };
123→
124→  /**
125→   * Handle manual refresh trigger (async materialized view refresh)
126→   */
127→  const handleManualRefresh = async () => {
128→    try {
129→      setRefreshing(true);
130→      setError(null);
131→
132→      // Trigger async refresh
133→      const job = await triggerRefresh();
134→      setRefreshJob(job);
135→
136→      // Start polling for job status and progress
137→      pollRefreshStatus();
138→
139→    } catch (err: any) {
140→      console.error('Failed to trigger refresh:', err);
141→      setError(err.response?.data?.message || 'Failed to trigger refresh');
142→      setRefreshing(false);
143→    }
144→  };
145→
146→  /**
147→   * Poll refresh status until completion
148→   */
149→  const pollRefreshStatus = async () => {
150→    // Clear any existing poll interval
151→    if (pollIntervalId) {
152→      clearInterval(pollIntervalId);
153→    }
154→
155→    const interval = setInterval(async () => {
156→      try {
157→        const status = await getRefreshStatus();
158→
159→        if (!status) {
160→          // No job running - refresh completed or failed
161→          clearInterval(interval);
162→          setPollIntervalId(null);
163→          setRefreshing(false);
164→          setRefreshJob(null);
165→
166→          // Reload assets and timestamp
167→          fetchAssets();
168→          fetchLastRefresh();
169→          return;
170→        }
171→
172→        setRefreshJob(status);
173→
174→        if (status.status === 'COMPLETED') {
175→          clearInterval(interval);
176→          setPollIntervalId(null);
177→          setRefreshing(false);
178→
179→          // Reload assets and timestamp
180→          fetchAssets();
181→          fetchLastRefresh();
182→        } else if (status.status === 'FAILED') {
183→          clearInterval(interval);
184→          setPollIntervalId(null);
185→          setRefreshing(false);
186→          setError(status.errorMessage || 'Refresh failed');
187→        }
188→
189→      } catch (err) {
190→        console.error('Failed to poll refresh status:', err);
191→        clearInterval(interval);
192→        setPollIntervalId(null);
193→        setRefreshing(false);
194→      }
195→    }, 2000); // Poll every 2 seconds
196→
197→    setPollIntervalId(interval);
198→  };
199→
200→  /**
201→   * Handle refresh button click (simple reload)
202→   */
203→  const handleRefresh = () => {
204→    fetchAssets();
205→    fetchLastRefresh();
206→  };
207→
208→  /**
209→   * Handle sort column click
210→   */
211→  const handleSort = (field: string) => {
212→    if (field === sortField) {
213→      // Toggle direction
214→      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
215→    } else {
216→      // New field, default to descending
217→      setSortField(field);
218→      setSortDirection('desc');
219→    }
220→  };
221→
222→  /**
223→   * Handle page change
224→   */
225→  const handlePageChange = (newPage: number) => {
226→    setCurrentPage(newPage);
227→  };
228→
229→  /**
230→   * Handle page size change
231→   */
232→  const handlePageSizeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
233→    setPageSize(parseInt(e.target.value, 10));
234→    setCurrentPage(0); // Reset to first page
235→  };
236→
237→  /**
238→   * Handle search
239→   */
240→  const handleSearch = (e: React.FormEvent) => {
241→    e.preventDefault();
242→    setCurrentPage(0); // Reset to first page
243→    fetchAssets();
244→  };
245→
246→  /**
247→   * Handle export to Excel
248→   */
249→  const handleExport = async () => {
250→    setExporting(true);
251→    setError(null);
252→
253→    try {
254→      await exportOutdatedAssets({
255→        searchTerm: searchTerm.trim() || undefined,
256→        minSeverity: (minSeverity || undefined) as any,
257→        adDomain: adDomain || undefined
258→      });
259→    } catch (err: any) {
260→      console.error('Failed to export outdated assets:', err);
261→      setError(err.message || 'Failed to export outdated assets');
262→    } finally {
263→      setExporting(false);
264→    }
265→  };
266→
267→  /**
268→   * Get severity badge class
269→   */
270→  const getSeverityBadgeClass = (count: number, severity: string): string => {
271→    if (count === 0) return 'badge bg-secondary';
