 38→export interface OutdatedAssetsParams {
 39→  page?: number;
 40→  size?: number;
 41→  sort?: string; // e.g., "oldestVulnDays,desc"
 42→  searchTerm?: string;
 43→  minSeverity?: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW';
 44→  adDomain?: string;
 45→}
