 59→/**
 60→ * Fetch paginated list of outdated assets
 61→ *
 62→ * @param params Query parameters (page, size, sort, search, filter)
 63→ * @returns Paginated list of outdated assets
 64→ */
 65→export async function getOutdatedAssets(
 66→  params: OutdatedAssetsParams = {}
 67→): Promise<OutdatedAssetsPage> {
 68→  const queryParams = new URLSearchParams();
 69→
 70→  if (params.page !== undefined) {
 71→    queryParams.append('page', params.page.toString());
 72→  }
 73→  if (params.size !== undefined) {
 74→    queryParams.append('size', params.size.toString());
 75→  }
 76→  if (params.sort) {
 77→    queryParams.append('sort', params.sort);
 78→  }
 79→  if (params.searchTerm) {
 80→    queryParams.append('searchTerm', params.searchTerm);
 81→  }
 82→  if (params.minSeverity) {
 83→    queryParams.append('minSeverity', params.minSeverity);
 84→  }
 85→  if (params.adDomain) {
 86→    queryParams.append('adDomain', params.adDomain);
 87→  }
 88→
 89→  const url = `/api/outdated-assets${queryParams.toString() ? '?' + queryParams.toString() : ''}`;
 90→  const response = await authenticatedGet(url);
 91→  return await response.json();
 92→}
