 94→/**
 95→ * Get the timestamp of the last materialized view refresh
 96→ *
 97→ * @returns Last refresh timestamp or null if no refresh has occurred
 98→ */
 99→export async function getLastRefreshTimestamp(): Promise<string | null> {
100→  try {
101→    const response = await authenticatedGet('/api/outdated-assets/last-refresh');
102→    if (response.status === 204) {
103→      return null;
104→    }
105→    const data: LastRefreshResponse = await response.json();
106→    return data.lastRefreshTimestamp;
107→  } catch (error: any) {
108→    // 204 No Content means no refresh has occurred yet
109→    if (error.response?.status === 204) {
110→      return null;
111→    }
112→    throw error;
113→  }
114→}
