138→/**
139→ * Export outdated assets to Excel with current filters
140→ *
141→ * @param params Optional filter parameters (searchTerm, minSeverity, adDomain)
142→ * @returns Promise<void> - Downloads the Excel file
143→ */
144→export async function exportOutdatedAssets(
145→  params: Pick<OutdatedAssetsParams, 'searchTerm' | 'minSeverity' | 'adDomain'> = {}
146→): Promise<void> {
147→  const queryParams = new URLSearchParams();
148→
149→  if (params.searchTerm) {
150→    queryParams.append('searchTerm', params.searchTerm);
151→  }
152→  if (params.minSeverity) {
153→    queryParams.append('minSeverity', params.minSeverity);
154→  }
155→  if (params.adDomain) {
156→    queryParams.append('adDomain', params.adDomain);
157→  }
158→
159→  const queryString = queryParams.toString();
160→  const url = `/api/outdated-assets/export${queryString ? '?' + queryString : ''}`;
161→
162→  const response = await fetch(url, {
163→    method: 'GET',
164→    credentials: 'include'
165→  });
166→
167→  if (!response.ok) {
168→    let errorMessage = `Failed to export outdated assets: ${response.status}`;
169→    try {
170→      const errorBody = await response.json();
171→      if (errorBody.error) {
172→        errorMessage = errorBody.error;
173→      }
174→    } catch {
175→      // Ignore JSON parse error, use default message
176→    }
177→    throw new Error(errorMessage);
178→  }
179→
180→  // Get filename from Content-Disposition header or use default
181→  const contentDisposition = response.headers.get('Content-Disposition');
182→  let filename = 'outdated_assets_export.xlsx';
183→  if (contentDisposition) {
184→    const match = contentDisposition.match(/filename="([^"]+)"/);
185→    if (match) {
186→      filename = match[1];
187→    }
188→  }
189→
190→  // Create blob and trigger download
191→  const blob = await response.blob();
192→  const downloadUrl = window.URL.createObjectURL(blob);
193→  const link = document.createElement('a');
194→  link.href = downloadUrl;
195→  link.download = filename;
196→  document.body.appendChild(link);
197→  link.click();
198→  document.body.removeChild(link);
199→  window.URL.revokeObjectURL(downloadUrl);
200→}
